function CustomerHistoryModal(props){
  var c=props.customer,bookings=props.bookings;
  var all=bookings.filter(function(b){return b.customer===c.name;}).sort(function(a,b2){return new Date(a.date)-new Date(b2.date);});
  var totalSale=all.reduce(function(s,b){return s+Number(b.amount);},0);
  var totalPaid=all.reduce(function(s,b){return s+Number(b.paidAmount||b.amount);},0);
  var totalBalance=totalSale-totalPaid;
  var totalProfit=all.reduce(function(s,b){return s+Number(b.amount)-Number(b.cost||0)-Number(b.commission||0);},0);
  var [histTab,setHistTab]=useState("office");

  function printOffice(){
    var rows=all.map(function(b,i){
      var bal=Number(b.amount)-Number(b.paidAmount||b.amount);
      var prof=Number(b.amount)-Number(b.cost||0)-Number(b.commission||0);
      return "<tr style='background:"+(i%2===0?"#fff":"#f0fdf4")+"'>"
        +"<td>"+b.date+"</td>"
        +"<td style='font-weight:700'>"+b.destination+"</td>"
        +"<td>"+b.type+"</td>"
        +"<td style='color:#16a34a;font-weight:700'>"+pkr(b.amount)+"</td>"
        +"<td style='color:#dc2626'>"+pkr(b.cost||0)+"</td>"
        +"<td>"+pkr(b.paidAmount||b.amount)+"</td>"
        +"<td style='color:"+(bal>0?"#dc2626":"#16a34a")+"'>"+pkr(bal)+"</td>"
        +"<td style='color:#b45309;font-weight:700'>"+pkr(prof)+"</td>"
        +"<td><span style='background:"+(b.status==="Paid"?"#dcfce7":"#fef9c3")+";padding:2px 7px;border-radius:20px;font-size:9px;font-weight:700'>"+b.status+"</span></td>"
        +"</tr>";
    }).join("");
    var html="<!DOCTYPE html><html><head><title>History: "+c.name+"</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',sans-serif;padding:15px}.hdr{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:2px solid #bbf7d0;padding-bottom:12px;margin-bottom:12px}.logo{height:50px}.info{text-align:right;font-size:11px;color:#6b7280;line-height:1.8}.title{font-size:16px;font-weight:900;color:#16a34a;margin-bottom:8px}.cards{display:flex;gap:8px;margin-bottom:12px;flex-wrap:wrap}.card{flex:1;background:#f0fdf4;border:1px solid #bbf7d0;border-radius:8px;padding:7px 10px;text-align:center}.cl{font-size:9px;color:#6b7280;font-weight:700;text-transform:uppercase}.cv{font-size:14px;font-weight:900;color:#16a34a}table{width:100%;border-collapse:collapse;font-size:10px}th{background:#f0fdf4;color:#16a34a;padding:6px 8px;text-align:left;font-size:9px;font-weight:800;text-transform:uppercase;border-bottom:2px solid #bbf7d0}td{padding:5px 8px;border-bottom:1px solid #e5e7eb}.foot{text-align:center;color:#9ca3af;font-size:9px;margin-top:10px;border-top:1px dashed #bbf7d0;padding-top:8px}@media print{*{-webkit-print-color-adjust:exact!important}}</style></head><body>"
    +"<div class='hdr'><img src='"+LOGO_URI+"' class='logo'/><div class='info'>"+AGENCY.name+"<br>"+AGENCY.phone1+" | "+AGENCY.email2+"<br>"+AGENCY.address+"</div></div>"
    +"<div class='title'>Office History — "+c.name+"</div>"
    +"<div class='cards'><div class='card'><div class='cl'>Total Bookings</div><div class='cv'>"+all.length+"</div></div><div class='card'><div class='cl'>Total Sale</div><div class='cv'>"+pkr(totalSale)+"</div></div><div class='card'><div class='cl'>Total Paid</div><div class='cv'>"+pkr(totalPaid)+"</div></div><div class='card'><div class='cl'>Balance</div><div class='cv' style='color:#dc2626'>"+pkr(totalBalance)+"</div></div><div class='card'><div class='cl'>Total Profit</div><div class='cv' style='color:#b45309'>"+pkr(totalProfit)+"</div></div></div>"
    +"<table><tr><th>Date</th><th>Destination</th><th>Package</th><th>Sale</th><th>Cost</th><th>Received</th><th>Balance</th><th>Profit</th><th>Status</th></tr>"+rows+"</table>"
    +"<div class='foot'>"+AGENCY.name+" | Printed: "+new Date().toLocaleDateString("en-PK")+"</div></body></html>";
    var w=window.open("","_blank");w.document.write(html);w.document.close();setTimeout(function(){w.print();},400);
  }

  function printClient(){
    var rows=all.map(function(b,i){
      var bal=Number(b.amount)-Number(b.paidAmount||b.amount);
      return "<tr style='background:"+(i%2===0?"#fff":"#f0fdf4")+"'>"
        +"<td>"+b.date+"</td>"
        +"<td style='font-weight:700'>"+b.destination+"</td>"
        +"<td>"+b.type+"</td>"
        +(b.description?"<td style='color:#6b7280;font-size:10px'>"+b.description+"</td>":"<td>--</td>")
        +"<td style='color:#16a34a;font-weight:700'>"+pkr(b.amount)+"</td>"
        +"<td style='color:#16a34a'>"+pkr(b.paidAmount||b.amount)+"</td>"
        +"<td style='color:"+(bal>0?"#dc2626":"#16a34a")+";font-weight:700'>"+pkr(bal)+"</td>"
        +"<td><span style='background:"+(b.status==="Paid"?"#dcfce7":"#fef9c3")+";padding:2px 7px;border-radius:20px;font-size:9px;font-weight:700'>"+b.status+"</span></td>"
        +"</tr>";
    }).join("");
    var html="<!DOCTYPE html><html><head><title>Statement: "+c.name+"</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',sans-serif;padding:15px}.hdr{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:2px solid #bbf7d0;padding-bottom:12px;margin-bottom:12px}.logo{height:55px}.info{text-align:right;font-size:11px;color:#6b7280;line-height:1.8}.title{font-size:18px;font-weight:900;color:#16a34a;margin-bottom:4px}.sub{color:#6b7280;font-size:12px;margin-bottom:12px}.cards{display:flex;gap:8px;margin-bottom:14px;flex-wrap:wrap}.card{flex:1;background:#f0fdf4;border:1px solid #bbf7d0;border-radius:9px;padding:8px 12px;text-align:center}.cl{font-size:9px;color:#6b7280;font-weight:700;text-transform:uppercase;margin-bottom:2px}.cv{font-size:15px;font-weight:900;color:#16a34a}table{width:100%;border-collapse:collapse;font-size:11px}th{background:#f0fdf4;color:#16a34a;padding:7px 8px;text-align:left;font-size:9px;font-weight:800;text-transform:uppercase;border-bottom:2px solid #bbf7d0}td{padding:6px 8px;border-bottom:1px solid #e5e7eb}.bal{background:#fee2e2;border:1px solid #fecaca;border-radius:8px;padding:10px 14px;margin-top:12px;text-align:center}.foot{text-align:center;color:#9ca3af;font-size:9px;margin-top:12px;border-top:1px dashed #bbf7d0;padding-top:8px;line-height:1.8}@media print{*{-webkit-print-color-adjust:exact!important}}</style></head><body>"
    +"<div class='hdr'><img src='"+LOGO_URI+"' class='logo'/><div class='info'>"+AGENCY.name+"<br>"+AGENCY.phone1+" | "+AGENCY.email2+"<br>"+AGENCY.address+"</div></div>"
    +"<div class='title'>Account Statement</div>"
    +"<div class='sub'>Client: <b>"+c.name+"</b> | Phone: "+c.phone+(c.passport?" | Passport: "+c.passport:"")+"</div>"
    +"<div class='cards'><div class='card'><div class='cl'>Total Services</div><div class='cv'>"+all.length+"</div></div><div class='card'><div class='cl'>Total Amount</div><div class='cv'>"+pkr(totalSale)+"</div></div><div class='card'><div class='cl'>Amount Paid</div><div class='cv'>"+pkr(totalPaid)+"</div></div><div class='card'><div class='cl'>Balance Due</div><div class='cv' style='color:#dc2626'>"+pkr(totalBalance)+"</div></div></div>"
    +"<table><tr><th>Date</th><th>Destination</th><th>Service</th><th>Description</th><th>Total</th><th>Paid</th><th>Balance</th><th>Status</th></tr>"+rows+"</table>"
    +(totalBalance>0?"<div class='bal'>⚠️ <b>Outstanding Balance: "+pkr(totalBalance)+"</b> — Baaki rakam jama karwayein</div>":"<div class='bal' style='background:#dcfce7;border-color:#bbf7d0'>✅ <b>Sab payments clear hain!</b></div>")
    +"<div class='foot'>"+AGENCY.name+"<br>"+AGENCY.phone1+" | "+AGENCY.email2+"<br>"+AGENCY.address+"</div></body></html>";
    var w=window.open("","_blank");w.document.write(html);w.document.close();setTimeout(function(){w.print();},400);
  }

  return(
    <Modal title={"History: "+c.name} onClose={props.onClose} wide={true}>
      {/* Summary cards */}
      <div style={{display:"flex",gap:8,marginBottom:12,flexWrap:"wrap"}}>
        {[["Bookings",all.length,C.accent],["Total Sale",pkr(totalSale),C.accent],["Paid",pkr(totalPaid),C.accent],["Balance",pkr(totalBalance),totalBalance>0?C.red:C.accent],["Profit",pkr(totalProfit),C.gold]].map(function(s){return(
          <div key={s[0]} style={{flex:1,minWidth:80,background:C.accentSoft,border:"1px solid "+C.border,borderRadius:9,padding:"8px 10px",textAlign:"center"}}>
            <div style={{color:C.muted,fontSize:9,fontWeight:700,textTransform:"uppercase"}}>{s[0]}</div>
            <div style={{color:s[2],fontWeight:900,fontSize:13}}>{s[1]}</div>
          </div>
        );})}
      </div>

      {/* 2 Tabs */}
      <div style={{display:"flex",gap:0,background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:8,overflow:"hidden",marginBottom:12}}>
        <button onClick={function(){setHistTab("office");}} style={{flex:1,padding:"8px 0",border:"none",background:histTab==="office"?C.accent:"transparent",color:histTab==="office"?"#fff":C.muted,fontWeight:700,cursor:"pointer",fontSize:12}}>
          🏢 Office View (Full Details)
        </button>
        <button onClick={function(){setHistTab("client");}} style={{flex:1,padding:"8px 0",border:"none",background:histTab==="client"?"#0284c7":"transparent",color:histTab==="client"?"#fff":C.muted,fontWeight:700,cursor:"pointer",fontSize:12}}>
          👤 Client Statement
        </button>
      </div>

      {/* Table */}
      <div style={{maxHeight:280,overflowY:"auto",border:"1.5px solid "+C.border,borderRadius:10,marginBottom:12}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:11,minWidth:histTab==="office"?700:550}}>
          <thead><tr style={{background:C.accentSoft}}>
            {histTab==="office"
              ?["Date","Destination","Package","Sale","Cost","Received","Balance","Profit","Status"].map(function(h){return <th key={h} style={{padding:"7px 8px",textAlign:"left",color:C.accent,fontWeight:800,fontSize:9,textTransform:"uppercase",position:"sticky",top:0,background:C.accentSoft}}>{h}</th>;})
              :["Date","Destination","Service","Description","Total","Paid","Balance","Status"].map(function(h){return <th key={h} style={{padding:"7px 8px",textAlign:"left",color:"#0284c7",fontWeight:800,fontSize:9,textTransform:"uppercase",position:"sticky",top:0,background:C.accentSoft}}>{h}</th>;})}
          </tr></thead>
          <tbody>
            {all.map(function(b,i){
              var bal=Number(b.amount)-Number(b.paidAmount||b.amount);
              var prof=Number(b.amount)-Number(b.cost||0)-Number(b.commission||0);
              return(
                <tr key={b.id} style={{borderTop:"1px solid "+C.border,background:i%2===0?"#fff":"#fafffe"}}>
                  <td style={{padding:"6px 8px",color:C.muted,fontSize:10}}>{b.date}</td>
                  <td style={{padding:"6px 8px",fontWeight:700}}>{b.destination}</td>
                  <td style={{padding:"6px 8px",fontSize:10,color:C.muted}}>{b.type}</td>
                  {histTab==="office"?(
                    <>
                      <td style={{padding:"6px 8px",color:C.accent,fontWeight:700}}>{pkr(b.amount)}</td>
                      <td style={{padding:"6px 8px",color:C.red,fontSize:10}}>{pkr(b.cost||0)}</td>
                      <td style={{padding:"6px 8px",color:C.accent}}>{pkr(b.paidAmount||b.amount)}</td>
                      <td style={{padding:"6px 8px",color:bal>0?C.red:C.accent,fontWeight:700}}>{pkr(bal)}</td>
                      <td style={{padding:"6px 8px",color:prof>=0?C.gold:C.red,fontWeight:700}}>{pkr(prof)}</td>
                    </>
                  ):(
                    <>
                      <td style={{padding:"6px 8px",color:C.muted,fontSize:10,maxWidth:120,overflow:"hidden",textOverflow:"ellipsis"}}>{b.description||"--"}</td>
                      <td style={{padding:"6px 8px",color:C.accent,fontWeight:700}}>{pkr(b.amount)}</td>
                      <td style={{padding:"6px 8px",color:C.accent}}>{pkr(b.paidAmount||b.amount)}</td>
                      <td style={{padding:"6px 8px",color:bal>0?C.red:C.accent,fontWeight:700}}>{pkr(bal)}</td>
                    </>
                  )}
                  <td style={{padding:"6px 8px"}}><Badge status={b.status}/></td>
                </tr>
              );
            })}
            {all.length===0&&<tr><td colSpan={9} style={{padding:16,textAlign:"center",color:C.muted}}>Koi booking nahi</td></tr>}
          </tbody>
        </table>
      </div>

      {/* Balance warning */}
      {totalBalance>0&&(
        <div style={{background:"#fee2e2",border:"1px solid #fecaca",borderRadius:8,padding:"8px 12px",marginBottom:10,fontSize:12,color:C.red,fontWeight:700}}>
          ⚠️ Outstanding Balance: {pkr(totalBalance)} — Client se baaki rakam leni hai
        </div>
      )}

      {/* Print buttons */}
      <div style={{display:"flex",gap:8}}>
        <button onClick={printOffice}
          style={{flex:1,background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"9px 0",fontWeight:800,cursor:"pointer",fontSize:12}}>
          🖨️ Print Office View
        </button>
        <button onClick={printClient}
          style={{flex:1,background:"#0284c7",color:"#fff",border:"none",borderRadius:8,padding:"9px 0",fontWeight:800,cursor:"pointer",fontSize:12}}>
          🖨️ Print Client Statement
        </button>
      </div>
    </Modal>
  );
}


// ─── PARTNER CASE MODAL ──────────────────────────────────────
function PartnerCaseModal(props){
  var emptyCase={id:"",title:"",status:"Active",date:"",clientAmount:"",partners:[],expenses:[],notes:""};
  var rawCase=props.caseItem?Object.assign({},props.caseItem):emptyCase;
  if(!Array.isArray(rawCase.partners)) rawCase.partners=[];
  if(!Array.isArray(rawCase.expenses)) rawCase.expenses=[];
  var [f,setF]=useState(rawCase);
  var [pName,setPName]=useState("");
  var [pAmt,setPAmt]=useState("");
  var [eName,setEName]=useState("");
  var [eAmt,setEAmt]=useState("");
  var [eTo,setETo]=useState("");


  var clientAmount=Number(f.clientAmount||0);
  var fPartners=Array.isArray(f.partners)?f.partners:[];
  var fExpenses=Array.isArray(f.expenses)?f.expenses:[];
  var totalInvested=fPartners.reduce(function(s,p){return s+Number(p.amount||0);},0);
  var totalExp=fExpenses.reduce(function(s,e){return s+Number(e.amount||0);},0);
  var netProfit=clientAmount-totalExp;

  function addPartner(){
    if(!pName)return;
    setF(Object.assign({},f,{partners:fPartners.concat([{name:pName,amount:Number(pAmt||0)}])}));
    setPName("");setPAmt("");
  }
  function addExpense(){
    if(!eName||!eAmt)return;
    setF(Object.assign({},f,{expenses:fExpenses.concat([{desc:eName,amount:Number(eAmt),to:eTo}])}));
    setEName("");setEAmt("");setETo("");
  }
  function removeP(i){setF(Object.assign({},f,{partners:fPartners.filter(function(_,j){return j!==i;})}));}
  function removeE(i){setF(Object.assign({},f,{expenses:fExpenses.filter(function(_,j){return j!==i;})}));}

  return(
    <Modal title={props.isNew?"New Partner Case":"Edit Partner Case"} onClose={props.onClose} wide={true}>
      <div style={{display:"flex",flexWrap:"wrap",justifyContent:"space-between"}}>
        <Field label="Case Title" value={f.title} onChange={function(v){setF(Object.assign({},f,{title:v}));}} half={true}/>
        <Field label="Status" value={f.status} onChange={function(v){setF(Object.assign({},f,{status:v}));}} options={["Active","In Progress","Visa Approved","Visa Refused","Closed"]} half={true}/>
        <Field label="Date" value={f.date} onChange={function(v){setF(Object.assign({},f,{date:v}));}} type="date" half={true}/>
        <Field label="Notes" value={f.notes} onChange={function(v){setF(Object.assign({},f,{notes:v}));}} half={true}/>
      </div>

      {/* Client Amount */}
      <div style={{background:"linear-gradient(135deg,#f0fdf4,#dcfce7)",border:"2px solid "+C.accent,borderRadius:12,padding:14,marginBottom:14}}>
        <div style={{fontWeight:800,color:C.accent,fontSize:13,marginBottom:8}}>💰 Client se Mila Total Amount</div>
        <div style={{display:"flex",gap:10,alignItems:"center"}}>
          <input
            type="number"
            value={f.clientAmount||""}
            onChange={function(e){setF(Object.assign({},f,{clientAmount:e.target.value}));}}
            placeholder="Client se kitna mila? (Rs.)"
            style={{flex:1,background:C.white,border:"2px solid "+C.accent,borderRadius:9,padding:"10px 14px",fontSize:14,fontWeight:700,color:C.accent,outline:"none"}}
          />
          {clientAmount>0&&<div style={{color:C.accent,fontWeight:900,fontSize:16,whiteSpace:"nowrap"}}>{pkr(clientAmount)}</div>}
        </div>
      </div>

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14,marginBottom:14}}>
        {/* Partners */}
        <div style={{background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:12,padding:14}}>
          <div style={{fontWeight:800,color:C.accent,fontSize:12,marginBottom:10}}>🤝 Partners / Investors</div>
          <div style={{display:"flex",gap:6,marginBottom:8}}>
            <input value={pName} onChange={function(e){setPName(e.target.value);}} placeholder="Partner name"
              style={{flex:2,background:C.white,border:"1.5px solid "+C.border,borderRadius:7,padding:"6px 9px",fontSize:12,outline:"none"}}/>
            <input value={pAmt} onChange={function(e){setPAmt(e.target.value);}} placeholder="Invested" type="number"
              style={{flex:1,background:C.white,border:"1.5px solid "+C.border,borderRadius:7,padding:"6px 9px",fontSize:12,outline:"none",minWidth:70}}/>
            <button onClick={addPartner} style={{background:C.accent,color:"#fff",border:"none",borderRadius:7,padding:"6px 10px",cursor:"pointer",fontWeight:700,fontSize:13}}>+</button>
          </div>
          {fPartners.map(function(p,i){return(
            <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"6px 0",borderBottom:"1px solid "+C.border,fontSize:12}}>
              <span style={{fontWeight:600}}>{p.name}</span>
              <div style={{display:"flex",gap:8,alignItems:"center"}}>
                <span style={{color:C.accent,fontWeight:700}}>{pkr(p.amount)}</span>
                <button onClick={function(){removeP(i);}} style={{background:C.redBg,border:"none",color:C.red,borderRadius:5,padding:"2px 7px",cursor:"pointer",fontSize:10}}>x</button>
              </div>
            </div>
          );})}
          <div style={{display:"flex",justifyContent:"space-between",fontWeight:800,color:C.accent,marginTop:8,fontSize:12,borderTop:"2px solid "+C.border,paddingTop:6}}>
            <span>Total Invested</span><span>{pkr(totalInvested)}</span>
          </div>
        </div>

        {/* Expenses */}
        <div style={{background:"#fef9f0",border:"1.5px solid #fde68a",borderRadius:12,padding:14}}>
          <div style={{fontWeight:800,color:C.gold,fontSize:12,marginBottom:10}}>💸 Expenses / Payments</div>
          <div style={{display:"flex",gap:4,marginBottom:8,flexWrap:"wrap"}}>
            <input value={eName} onChange={function(e){setEName(e.target.value);}} placeholder="Description"
              style={{flex:2,background:C.white,border:"1.5px solid #fde68a",borderRadius:7,padding:"6px 9px",fontSize:12,outline:"none",minWidth:70}}/>
            <input value={eTo} onChange={function(e){setETo(e.target.value);}} placeholder="To whom"
              style={{flex:1,background:C.white,border:"1.5px solid #fde68a",borderRadius:7,padding:"6px 9px",fontSize:12,outline:"none",minWidth:60}}/>
            <input value={eAmt} onChange={function(e){setEAmt(e.target.value);}} placeholder="Amount" type="number"
              style={{flex:1,background:C.white,border:"1.5px solid #fde68a",borderRadius:7,padding:"6px 9px",fontSize:12,outline:"none",minWidth:60}}/>
            <button onClick={addExpense} style={{background:C.gold,color:"#fff",border:"none",borderRadius:7,padding:"6px 10px",cursor:"pointer",fontWeight:700,fontSize:13}}>+</button>
          </div>
          {fExpenses.map(function(e,i){return(
            <div key={i} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"5px 0",borderBottom:"1px solid #fde68a",fontSize:12}}>
              <div><span style={{fontWeight:600}}>{e.desc}</span>{e.to&&<span style={{color:C.muted,fontSize:10}}> → {e.to}</span>}</div>
              <div style={{display:"flex",gap:8,alignItems:"center"}}>
                <span style={{color:C.red,fontWeight:700}}>{pkr(e.amount)}</span>
                <button onClick={function(){removeE(i);}} style={{background:C.redBg,border:"none",color:C.red,borderRadius:5,padding:"2px 7px",cursor:"pointer",fontSize:10}}>x</button>
              </div>
            </div>
          );})}
          <div style={{display:"flex",justifyContent:"space-between",fontWeight:800,color:C.red,marginTop:8,fontSize:12,borderTop:"2px solid #fde68a",paddingTop:6}}>
            <span>Total Expenses</span><span>{pkr(totalExp)}</span>
          </div>
        </div>
      </div>

      {/* Summary Cards */}
      <div style={{display:"flex",gap:10,marginBottom:14,flexWrap:"wrap"}}>
        {[
          ["Client Amount",pkr(clientAmount),C.accent,C.accentSoft,C.border],
          ["Total Expenses",pkr(totalExp),C.red,"#fef9f0","#fde68a"],
          ["Total Investments",pkr(totalInvested),C.gold,"#fffbeb","#fde68a"],
          ["Net Profit (to divide)",pkr(clientAmount-totalExp-totalInvested),C.accent,C.white,C.border],
          ["Per Partner Share",pkr(fPartners.length>0?Math.round((clientAmount-totalExp-totalInvested)/fPartners.length):0),"#7c3aed","#f5f3ff","#ddd6fe"]
        ].map(function(s){return(
          <div key={s[0]} style={{flex:1,minWidth:110,background:s[3],border:"1.5px solid "+s[4],borderRadius:10,padding:"10px 12px",textAlign:"center"}}>
            <div style={{color:C.muted,fontSize:9,fontWeight:700,textTransform:"uppercase",marginBottom:3}}>{s[0]}</div>
            <div style={{color:s[2],fontWeight:900,fontSize:15}}>{s[1]}</div>
          </div>
        );})}
      </div>

      {/* Per Partner Breakdown Table */}
      {f.partners.length>0&&(
        <div style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:12,padding:14,marginBottom:14}}>
          <div style={{fontWeight:800,color:C.accent,fontSize:12,marginBottom:10}}>📊 Per Partner Breakdown</div>
          {/* Formula Box */}
          <div style={{background:"#f0fdf4",border:"2px solid "+C.border,borderRadius:10,padding:"10px 14px",marginBottom:12}}>
            <div style={{fontWeight:800,color:C.accent,fontSize:12,marginBottom:8}}>📊 Hisaab:</div>
            <div style={{fontSize:12,display:"flex",flexWrap:"wrap",gap:6,alignItems:"center"}}>
              <span style={{background:"#dcfce7",color:C.accent,padding:"3px 9px",borderRadius:7,fontWeight:700}}>{pkr(clientAmount)} Client</span>
              <span style={{color:C.red,fontWeight:700}}>− {pkr(totalExp)} Expenses</span>
              <span style={{color:C.red,fontWeight:700}}>− {pkr(totalInvested)} Investments</span>
              <span style={{fontWeight:900,color:C.accent,fontSize:14}}>= {pkr(clientAmount-totalExp-totalInvested)} Divide Hoga</span>
            </div>
            <div style={{color:C.muted,fontSize:11,marginTop:5}}>
              {pkr(clientAmount-totalExp-totalInvested)} ÷ {fPartners.length} partners = <b style={{color:C.accent}}>{pkr(fPartners.length>0?Math.round((clientAmount-totalExp-totalInvested)/fPartners.length):0)}</b> har partner ko
            </div>
          </div>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:12,marginBottom:10}}>
            <thead>
              <tr style={{background:C.accentSoft}}>
                {["Partner","Investment Lagaya","Investment Wapas","Profit Share","TOTAL MILEGA"].map(function(h){
                  return <th key={h} style={{padding:"9px 10px",textAlign:"left",color:C.accent,fontWeight:800,fontSize:9,textTransform:"uppercase",borderBottom:"2px solid "+C.border}}>{h}</th>;
                })}
              </tr>
            </thead>
            <tbody>
              {fPartners.map(function(p,i){
                var invested=Number(p.amount||0);
                var netToDivide=clientAmount-totalExp-totalInvested;
                var profitShare=fPartners.length>0?Math.round(netToDivide/fPartners.length):0;
                var total=invested+profitShare;
                return(
                  <tr key={i} style={{borderTop:"1px solid "+C.border,background:i%2===0?"#fff":"#f0fdf4"}}>
                    <td style={{padding:"10px",fontWeight:800,fontSize:14}}>{p.name}</td>
                    <td style={{padding:"10px",color:invested>0?C.accent:C.muted,fontWeight:600}}>
                      {invested>0?pkr(invested):"—"}
                    </td>
                    <td style={{padding:"10px"}}>
                      {invested>0
                        ?<span style={{background:"#dcfce7",color:C.accent,padding:"3px 9px",borderRadius:20,fontSize:11,fontWeight:700}}>+ {pkr(invested)}</span>
                        :<span style={{color:C.muted,fontSize:11}}>—</span>}
                    </td>
                    <td style={{padding:"10px",color:profitShare>=0?C.gold:C.red,fontWeight:700}}>
                      <div style={{fontSize:11,color:C.muted}}>{pkr(netToDivide)} ÷ {fPartners.length}</div>
                      <div style={{fontSize:14,fontWeight:900}}>{pkr(profitShare)}</div>
                    </td>
                    <td style={{padding:"10px",background:C.accentSoft,borderLeft:"2px solid "+C.accent}}>
                      <div style={{fontWeight:900,fontSize:16,color:C.accent}}>{pkr(total)}</div>
                      <div style={{fontSize:10,color:C.muted,marginTop:2}}>
                        {invested>0?pkr(invested)+" wapas + ":""}{pkr(profitShare)} profit
                      </div>
                    </td>
                  </tr>
                );
              })}
              {fExpenses.map(function(e,i){return(
                <tr key={"exp"+i} style={{borderTop:"1px solid #fde68a",background:"#fffbeb"}}>
                  <td colSpan={3} style={{padding:"8px 10px",color:C.gold,fontWeight:600,fontSize:12}}>
                    💸 {e.desc}{e.to?" → "+e.to:""}
                  </td>
                  <td style={{padding:"8px 10px",color:C.red,fontWeight:700,fontSize:12}}>Expense</td>
                  <td style={{padding:"8px 10px",color:C.red,fontWeight:800,borderLeft:"2px solid #fde68a"}}>− {pkr(e.amount)}</td>
                </tr>
              );})}
            </tbody>
            <tfoot>
              <tr style={{borderTop:"3px solid "+C.accent,background:"#dcfce7"}}>
                <td colSpan={2} style={{padding:"10px",fontWeight:800,fontSize:13,color:C.accent}}>
                  Client: {pkr(clientAmount)}
                </td>
                <td colSpan={2} style={{padding:"10px",color:C.red,fontWeight:700,fontSize:12}}>
                  Out: {pkr(totalExp+totalInvested)}
                </td>
                <td style={{padding:"10px",fontWeight:900,fontSize:14,color:C.accent,borderLeft:"2px solid "+C.accent}}>
                  Baki: {pkr(clientAmount-totalExp-totalInvested)}
                </td>
              </tr>
            </tfoot>
          </table>
        </div>
      )}

      <button onClick={function(){props.onSave(Object.assign({},f,{id:f.id||uid("PC"),clientAmount:Number(f.clientAmount||0)}));}}
        style={{width:"100%",background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"12px 0",fontWeight:800,cursor:"pointer",fontSize:14}}>
        Save Case
      </button>
    </Modal>
  );
}

function PartnerCasesTab(props){
  var cases=Array.isArray(props.cases)?props.cases:[];
  var setCases=props.setCases,showToast=props.showToast;
  var [showForm,setShowForm]=useState(false);
  var [editCase,setEditCase]=useState(null);
  var [viewCase,setViewCase]=useState(null);

  function saveCase(c){
    var u=editCase?cases.map(function(x){return x.id===c.id?c:x;}):cases.concat([c]);
    setCases(u);sv("olympia_cases",u);fbSave("olympia_cases",u);showToast();setShowForm(false);setEditCase(null);
  }
  function delCase(id){var u=cases.filter(function(x){return x.id!==id;});setCases(u);sv("olympia_cases",u);fbSave("olympia_cases",u);showToast();}

  var [cSearch,setCSearch]=useState("");
  var [cFilter,setCFilter]=useState("active");
  var isDone=function(c){return c.status==="Visa Approved"||c.status==="Visa Refused"||c.status==="Closed";};
  var fCases=cases.filter(function(c){
    var ms=!cSearch||(c.title||"").toLowerCase().includes(cSearch.toLowerCase());
    if(cFilter==="active") return ms&&!isDone(c);
    if(cFilter==="closed") return ms&&isDone(c);
    return ms;
  }).sort(function(a,b){return(isDone(a)?1:0)-(isDone(b)?1:0);});

  return(<div>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8,flexWrap:"wrap",gap:8}}>
      <h2 style={{margin:0,fontSize:16,fontWeight:800,color:C.accent}}>Partner Cases</h2>
      <div style={{display:"flex",gap:6,alignItems:"center"}}>
        <input value={cSearch} onChange={function(e){setCSearch(e.target.value);}} placeholder="Search..."
          style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:8,padding:"6px 10px",fontSize:12,outline:"none",minWidth:120}}/>
        <button onClick={function(){setEditCase(null);setShowForm(true);}} style={{background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"7px 14px",fontWeight:800,cursor:"pointer",fontSize:12}}>+ New Case</button>
      </div>
    </div>
    <div style={{display:"flex",gap:6,marginBottom:10,flexWrap:"wrap"}}>
      {[["active","🔄 Active"],["closed","✅ Done"],["all","All"]].map(function(fl){
        var cnt=fl[0]==="active"?cases.filter(function(c){return !isDone(c);}).length:fl[0]==="closed"?cases.filter(function(c){return isDone(c);}).length:cases.length;
        return(
          <button key={fl[0]} onClick={function(){setCFilter(fl[0]);}}
            style={{padding:"5px 12px",border:"1.5px solid "+C.border,borderRadius:8,background:cFilter===fl[0]?C.accent:"#fff",color:cFilter===fl[0]?"#fff":C.muted,fontWeight:700,cursor:"pointer",fontSize:11}}>
            {fl[1]} ({cnt})
          </button>
        );
      })}
    </div>
    {fCases.length===0&&<div style={{color:C.muted,fontSize:13,padding:"20px 0"}}>Koi case nahi</div>}
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(280px,1fr))",gap:14}}>
      {fCases.map(function(c){
        var pArr=Array.isArray(c.partners)?c.partners:[];
        var eArr=Array.isArray(c.expenses)?c.expenses:[];
        var totalIn=Number(c.clientAmount||pArr.reduce(function(s,p){return s+Number(p.amount||0);},0));
        var totalExp=eArr.reduce(function(s,e){return s+Number(e.amount||0);},0);
        var net=totalIn-totalExp;
        return(
          <div key={c.id} style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:14,padding:18,boxShadow:C.shadow}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:10}}>
              <div><div style={{fontWeight:800,fontSize:14}}>{c.title}</div><div style={{color:C.muted,fontSize:11}}>{c.date}</div></div>
              <Badge status={c.status}/>
            </div>
            <div style={{display:"flex",gap:10,marginBottom:10,flexWrap:"wrap"}}>
              <div style={{fontSize:11}}><span style={{color:C.muted}}>Partners: </span><span style={{fontWeight:700,color:C.accent}}>{pArr.length}</span></div>
              <div style={{fontSize:11}}><span style={{color:C.muted}}>In: </span><span style={{fontWeight:700,color:C.accent}}>{pkr(totalIn)}</span></div>
              <div style={{fontSize:11}}><span style={{color:C.muted}}>Out: </span><span style={{fontWeight:700,color:C.red}}>{pkr(totalExp)}</span></div>
              <div style={{fontSize:11}}><span style={{color:C.muted}}>Profit: </span><span style={{fontWeight:700,color:net>=0?C.gold:C.red}}>{pkr(net)}</span></div>
            </div>
            {c.notes&&<div style={{color:C.muted,fontSize:11,marginBottom:10,fontStyle:"italic"}}>{c.notes}</div>}
            <div style={{display:"flex",gap:6}}>
              <button onClick={function(){setViewCase(c);}} style={{flex:1,background:C.accentSoft,border:"1px solid "+C.accent,color:C.accent,borderRadius:7,padding:"5px 0",cursor:"pointer",fontSize:11,fontWeight:700}}>View</button>
              <button onClick={function(){setEditCase(c);setShowForm(true);}} style={{flex:1,background:"#fffbeb",border:"1px solid #fde68a",color:C.gold,borderRadius:7,padding:"5px 0",cursor:"pointer",fontSize:11,fontWeight:700}}>Edit</button>
              <button onClick={function(){delCase(c.id);}} style={{flex:1,background:C.redBg,border:"1px solid #fecaca",color:C.red,borderRadius:7,padding:"5px 0",cursor:"pointer",fontSize:11,fontWeight:700}}>Del</button>
            </div>
          </div>
        );
      })}
    </div>

    {viewCase&&(
      <Modal title={"Case: "+viewCase.title} onClose={function(){setViewCase(null);}} wide={true}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
          <button onClick={function(){setEditCase(viewCase);setShowForm(true);setViewCase(null);}}
            style={{background:"#fffbeb",border:"1px solid #fde68a",color:C.gold,borderRadius:8,padding:"7px 16px",fontWeight:800,cursor:"pointer",fontSize:13}}>
            ✏️ Edit
          </button>
          <button onClick={function(){
            var vp=Array.isArray(viewCase.partners)?viewCase.partners:[];
            var ve=Array.isArray(viewCase.expenses)?viewCase.expenses:[];
            var vc=Number(viewCase.clientAmount||0);
            var vi=vp.reduce(function(s,p){return s+Number(p.amount||0);},0);
            var vx=ve.reduce(function(s,e){return s+Number(e.amount||0);},0);
            var vnd=vc-vx-vi;
            var vps=vp.length>0?Math.round(vnd/vp.length):0;
            var partnerRows=vp.map(function(p){
              var inv=Number(p.amount||0);
              var total=inv+vps;
              return "<tr><td style='padding:10px;font-weight:800;font-size:15px'>"+p.name+"</td><td style='padding:10px;color:#16a34a;font-weight:700'>"+pkr(inv||0)+"</td><td style='padding:10px'>"+( inv>0?"<span style='background:#dcfce7;color:#16a34a;padding:2px 8px;border-radius:20px;font-size:11px;font-weight:700'>+ "+pkr(inv)+"</span>":"—")+"</td><td style='padding:10px;color:#b45309;font-weight:700'><div style='font-size:10px;color:#6b7280'>"+pkr(vnd)+" ÷ "+vp.length+"</div><div style='font-size:14px;font-weight:900'>"+pkr(vps)+"</div></td><td style='padding:10px;background:#f0fdf4;border-left:2px solid #16a34a'><div style='font-weight:900;font-size:16px;color:#16a34a'>"+pkr(total)+"</div><div style='font-size:10px;color:#6b7280'>"+(inv>0?pkr(inv)+" wapas + ":"")+pkr(vps)+" profit</div></td></tr>";
            }).join("");
            var expRows=ve.map(function(e){
              return "<tr style='background:#fffbeb'><td colspan='3' style='padding:8px 10px;color:#b45309;font-weight:600'>💸 "+e.desc+(e.to?" → "+e.to:"")+"</td><td style='padding:8px 10px;color:#dc2626'>Expense</td><td style='padding:8px 10px;color:#dc2626;font-weight:800;border-left:2px solid #fde68a'>− "+pkr(e.amount)+"</td></tr>";
            }).join("");
            var html="<!DOCTYPE html><html><head><title>"+viewCase.title+"</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Arial,sans-serif;background:#f0fdf4;padding:20px;color:#1f2937}.box{background:#fff;border-radius:14px;padding:28px;max-width:680px;margin:0 auto;border:2px solid #bbf7d0}.title{font-size:20px;font-weight:900;color:#16a34a;margin-bottom:4px}.sub{color:#6b7280;font-size:12px;margin-bottom:16px}.formula{background:#f0fdf4;border:2px solid #bbf7d0;border-radius:10px;padding:12px 16px;margin-bottom:16px;font-size:12px}.fl{font-weight:700;color:#16a34a;font-size:11px;margin-bottom:6px}.fr{display:flex;flex-wrap:wrap;gap:6px;align-items:center}.tag{background:#dcfce7;color:#16a34a;padding:3px 9px;border-radius:7px;font-weight:700}.cards{display:flex;gap:10px;flex-wrap:wrap;margin-bottom:16px}.card{flex:1;min-width:90px;background:#f0fdf4;border:1px solid #bbf7d0;border-radius:9px;padding:9px 11px;text-align:center}.cl{color:#6b7280;font-size:9px;font-weight:700;text-transform:uppercase;margin-bottom:2px}.cv{font-size:15px;font-weight:900;color:#16a34a}table{width:100%;border-collapse:collapse;font-size:12px}th{background:#f0fdf4;color:#16a34a;padding:9px 10px;text-align:left;font-size:9px;font-weight:800;text-transform:uppercase;border-bottom:2px solid #bbf7d0}td{padding:8px 10px;border-bottom:1px solid #d1f0dd}.foot{text-align:center;color:#9ca3af;font-size:10px;margin-top:16px;padding-top:12px;border-top:1px dashed #bbf7d0}@media print{body{background:#fff!important}*{-webkit-print-color-adjust:exact!important}}</style></head><body><div class='box'><div class='title'>"+viewCase.title+"</div><div class='sub'>Date: "+viewCase.date+(viewCase.notes?" | "+viewCase.notes:"")+" | Status: "+viewCase.status+"</div><div class='cards'><div class='card'><div class='cl'>Client Amount</div><div class='cv'>"+pkr(vc)+"</div></div><div class='card'><div class='cl'>Expenses</div><div class='cv' style='color:#dc2626'>"+pkr(vx)+"</div></div><div class='card'><div class='cl'>Investments</div><div class='cv' style='color:#b45309'>"+pkr(vi)+"</div></div><div class='card'><div class='cl'>Net to Divide</div><div class='cv'>"+pkr(vnd)+"</div></div><div class='card'><div class='cl'>Per Partner</div><div class='cv' style='color:#7c3aed'>"+pkr(vps)+"</div></div></div><div class='formula'><div class='fl'>📊 Hisaab:</div><div class='fr'><span class='tag'>"+pkr(vc)+"</span><span style='color:#dc2626'>− "+pkr(vx)+" Expenses</span><span style='color:#dc2626'>− "+pkr(vi)+" Investments</span><span style='font-weight:900;color:#16a34a;font-size:14px'>= "+pkr(vnd)+" ÷ "+vp.length+" = "+pkr(vps)+" each</span></div></div><table><tr><th>Partner</th><th>Investment</th><th>Settled</th><th>Profit Share</th><th>TOTAL MILEGA</th></tr>"+partnerRows+expRows+"<tr style='border-top:3px solid #16a34a;background:#dcfce7'><td colspan='2' style='padding:10px;font-weight:800;color:#16a34a'>Client: "+pkr(vc)+"</td><td colspan='2' style='padding:10px;color:#dc2626;font-weight:700'>Out: "+pkr(vx+vi)+"</td><td style='padding:10px;font-weight:900;font-size:14px;color:#16a34a;border-left:2px solid #16a34a'>Baki: "+pkr(vnd)+"</td></tr></table><div class='foot'>Unofficial Record — "+viewCase.date+"</div></div></body></html>";
            var w=window.open("","_blank");w.document.write(html);w.document.close();setTimeout(function(){w.print();},400);
          }} style={{background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"7px 16px",fontWeight:800,cursor:"pointer",fontSize:13}}>
            🖨️ Print
          </button>
        </div>
        {function(){
          var vp=Array.isArray(viewCase.partners)?viewCase.partners:[];
          var ve=Array.isArray(viewCase.expenses)?viewCase.expenses:[];
          var vc=Number(viewCase.clientAmount||0);
          var vi=vp.reduce(function(s,p){return s+Number(p.amount||0);},0);
          var vx=ve.reduce(function(s,e){return s+Number(e.amount||0);},0);
          var vnd=vc-vx-vi;
          var vps=vp.length>0?Math.round(vnd/vp.length):0;
          return(
            <div>
              {/* Summary cards */}
              <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:14}}>
                {[["Client Amount",pkr(vc),C.accent,"#dcfce7"],["Expenses",pkr(vx),C.red,"#fef9f0"],["Investments",pkr(vi),C.gold,"#fffbeb"],["Net to Divide",pkr(vnd),C.accent,"#f0fdf4"],["Per Partner",pkr(vps),"#7c3aed","#f5f3ff"]].map(function(s){return(
                  <div key={s[0]} style={{flex:1,minWidth:90,background:s[3],borderRadius:10,padding:"9px 11px",textAlign:"center",border:"1px solid "+C.border}}>
                    <div style={{color:C.muted,fontSize:9,fontWeight:700,textTransform:"uppercase",marginBottom:2}}>{s[0]}</div>
                    <div style={{color:s[2],fontWeight:900,fontSize:14}}>{s[1]}</div>
                  </div>
                );})}
              </div>
              {/* Formula */}
              <div style={{background:"#f0fdf4",border:"2px solid "+C.border,borderRadius:10,padding:"10px 14px",marginBottom:12,fontSize:12}}>
                <div style={{fontWeight:800,color:C.accent,marginBottom:5}}>📊 Hisaab:</div>
                <div style={{display:"flex",flexWrap:"wrap",gap:6,alignItems:"center"}}>
                  <span style={{background:"#dcfce7",color:C.accent,padding:"3px 9px",borderRadius:7,fontWeight:700}}>{pkr(vc)}</span>
                  <span style={{color:C.red}}>− {pkr(vx)} Expenses</span>
                  <span style={{color:C.red}}>− {pkr(vi)} Investments</span>
                  <span style={{fontWeight:900,color:C.accent,fontSize:14}}>= {pkr(vnd)} ÷ {vp.length} = {pkr(vps)} each</span>
                </div>
              </div>
              {/* Breakdown table */}
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:12,marginBottom:10}}>
                <thead><tr style={{background:C.accentSoft}}>
                  {["Partner","Investment","Settled","Profit Share","TOTAL MILEGA"].map(function(h){return <th key={h} style={{padding:"9px 10px",textAlign:"left",color:C.accent,fontWeight:800,fontSize:9,textTransform:"uppercase",borderBottom:"2px solid "+C.border}}>{h}</th>;})}
                </tr></thead>
                <tbody>
                  {vp.map(function(p,i){
                    var inv=Number(p.amount||0);
                    var share=vps;
                    var total=inv+share;
                    return(
                      <tr key={i} style={{borderTop:"1px solid "+C.border,background:i%2===0?"#fff":"#f0fdf4"}}>
                        <td style={{padding:"10px",fontWeight:800,fontSize:14}}>{p.name}</td>
                        <td style={{padding:"10px",color:inv>0?C.accent:C.muted}}>{inv>0?pkr(inv):"—"}</td>
                        <td style={{padding:"10px"}}>
                          {inv>0?<span style={{background:"#dcfce7",color:C.accent,padding:"2px 8px",borderRadius:20,fontSize:11,fontWeight:700}}>+ {pkr(inv)}</span>:<span style={{color:C.muted}}>—</span>}
                        </td>
                        <td style={{padding:"10px",color:C.gold,fontWeight:700}}>
                          <div style={{fontSize:10,color:C.muted}}>{pkr(vnd)} ÷ {vp.length}</div>
                          <div style={{fontSize:14,fontWeight:900}}>{pkr(share)}</div>
                        </td>
                        <td style={{padding:"10px",background:C.accentSoft,borderLeft:"2px solid "+C.accent}}>
                          <div style={{fontWeight:900,fontSize:16,color:C.accent}}>{pkr(total)}</div>
                          <div style={{fontSize:10,color:C.muted}}>{inv>0?pkr(inv)+" wapas + ":""}{pkr(share)} profit</div>
                        </td>
                      </tr>
                    );
                  })}
                  {ve.map(function(e,i){return(
                    <tr key={"e"+i} style={{borderTop:"1px solid #fde68a",background:"#fffbeb"}}>
                      <td colSpan={3} style={{padding:"8px 10px",color:C.gold,fontWeight:600}}>💸 {e.desc}{e.to?" → "+e.to:""}</td>
                      <td style={{padding:"8px 10px",color:C.red,fontWeight:700}}>Expense</td>
                      <td style={{padding:"8px 10px",color:C.red,fontWeight:800,borderLeft:"2px solid #fde68a"}}>− {pkr(e.amount)}</td>
                    </tr>
                  );})}
                </tbody>
              </table>
            </div>
          );
        }()}
      </Modal>
    )}
    {showForm&&<PartnerCaseModal caseItem={editCase} isNew={!editCase} onSave={saveCase} onClose={function(){setShowForm(false);setEditCase(null);}}/>}
  </div>);
}

// ─── REPORTS TAB ─────────────────────────────────────────────
function Reports(props){
  var bookings=props.bookings,expenses=props.expenses;
  var [mode,setMode]=useState("month");
  var [mo,setMo]=useState(new Date().getMonth());
  var [yr,setYr]=useState(new Date().getFullYear());
  var [yrOnly,setYrOnly]=useState(new Date().getFullYear());

  var filtered=useMemo(function(){
    return {
      bookings:bookings.filter(function(b){
        if(!b.date)return false;
        var d=new Date(b.date);
        if(mode==="year")return d.getFullYear()===yrOnly;
        return d.getMonth()===mo&&d.getFullYear()===yr;
      }),
      expenses:expenses.filter(function(e){
        if(!e.date)return false;
        var d=new Date(e.date);
        if(mode==="year")return d.getFullYear()===yrOnly;
        return d.getMonth()===mo&&d.getFullYear()===yr;
      })
    };
  },[bookings,expenses,mode,mo,yr,yrOnly]);

  var mB=filtered.bookings,mE=filtered.expenses;
  var mRev=mB.filter(function(b){return b.status==="Paid";}).reduce(function(s,b){return s+Number(b.amount);},0);
  var mExp=mE.reduce(function(s,e){return s+Number(e.amount);},0);
  var mProfit=mB.reduce(function(s,b){return s+Number(b.amount)-Number(b.cost||0)-Number(b.commission||0);},0);
  var mPro=mRev-mExp;
  var pend=mB.filter(function(b){return b.status==="Pending";}).reduce(function(s,b){return s+Number(b.amount);},0);
  var acct=mB.filter(function(b){return b.status==="Paid";}).reduce(function(a,b){var k=b.account||"Bank Alfalah";a[k]=(a[k]||0)+Number(b.amount);return a;},{});
  var expCat=mE.reduce(function(a,e){a[e.category]=(a[e.category]||0)+e.amount;return a;},{});
  var period=mode==="year"?String(yrOnly):MONTHS[mo]+" "+yr;

  var printRep=function(){
    var rows1=mB.map(function(b){var p=Number(b.amount)-Number(b.cost||0)-Number(b.commission||0);return "<tr><td>"+b.customer+"</td><td>"+b.destination+"</td><td>"+b.date+"</td><td style='color:#16a34a'>"+pkr(b.amount)+"</td><td style='color:#dc2626'>"+pkr(b.cost||0)+"</td><td style='color:#dc2626'>"+pkr(b.commission||0)+"</td><td style='color:"+(p>=0?"#16a34a":"#dc2626")+"'>"+pkr(p)+"</td><td>"+b.status+"</td><td>"+(b.account||"--")+"</td></tr>";}).join("")||"<tr><td colspan='9' style='color:#9ca3af;padding:10px'>No bookings</td></tr>";
    var rows2=mE.map(function(e){return "<tr><td>"+e.description+"</td><td>"+e.category+"</td><td>"+e.date+"</td><td style='color:#dc2626'>"+pkr(e.amount)+"</td><td>"+(e.account||"--")+"</td></tr>";}).join("")||"<tr><td colspan='5' style='color:#9ca3af;padding:10px'>No expenses</td></tr>";
    var acctRows=Object.entries(acct).map(function(kv){return "<tr><td>"+kv[0]+"</td><td style='color:#16a34a'>"+pkr(kv[1])+"</td></tr>";}).join("")||"<tr><td colspan='2' style='color:#9ca3af;padding:10px'>None</td></tr>";
    var w=window.open("","_blank");
    var html="<!DOCTYPE html><html><head><title>Report "+period+"</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Arial,sans-serif;background:#f0fdf4;padding:20px;color:#1f2937}.wrap{max-width:760px;margin:0 auto;background:#fff;border-radius:14px;padding:30px;border:2px solid #bbf7d0}.hdr{display:flex;align-items:flex-start;justify-content:space-between;border-bottom:2px solid #bbf7d0;padding-bottom:14px;margin-bottom:18px}.logo{height:55px;width:auto}.hr{text-align:right;color:#6b7280;font-size:11px;line-height:1.8}.ht{color:#16a34a;font-size:16px;font-weight:900}.stats{display:flex;gap:10px;margin-bottom:16px;flex-wrap:wrap}.stat{background:#f0fdf4;border:1.5px solid #bbf7d0;border-radius:9px;padding:10px 14px;flex:1;min-width:90px}.sl{color:#6b7280;font-size:9px;font-weight:700;text-transform:uppercase}.sv{font-size:16px;font-weight:800;margin-top:2px}table{width:100%;border-collapse:collapse;font-size:11px;margin-bottom:16px}th{background:#f0fdf4;color:#16a34a;padding:8px 10px;text-align:left;font-size:9px;font-weight:800;text-transform:uppercase}td{padding:7px 10px;border-bottom:1px solid #d1f0dd}h3{color:#16a34a;font-size:12px;margin:14px 0 7px;padding-bottom:4px;border-bottom:1px solid #bbf7d0}.foot{text-align:center;color:#9ca3af;font-size:9px;margin-top:12px;border-top:1px dashed #bbf7d0;padding-top:8px;line-height:1.8}@media print{body{background:#fff!important;padding:8px}*{-webkit-print-color-adjust:exact!important}}</style></head><body><div class='wrap'><div class='hdr'><img src='"+LOGO_URI+"' class='logo'/><div class='hr'><div class='ht'>Financial Report</div><div>"+period+"</div><div>"+dstr()+"</div></div></div><div class='stats'><div class='stat'><div class='sl'>Revenue</div><div class='sv' style='color:#16a34a'>"+pkr(mRev)+"</div></div><div class='stat'><div class='sl'>Booking Profit</div><div class='sv' style='color:#b45309'>"+pkr(mProfit)+"</div></div><div class='stat'><div class='sl'>Expenses</div><div class='sv' style='color:#dc2626'>"+pkr(mExp)+"</div></div><div class='stat'><div class='sl'>Net Profit</div><div class='sv' style='color:"+(mPro>=0?"#b45309":"#dc2626")+"'>"+pkr(mPro)+"</div></div><div class='stat'><div class='sl'>Pending</div><div class='sv' style='color:#d97706'>"+pkr(pend)+"</div></div></div><h3>Account-wise Income</h3><table><tr><th>Account</th><th>Amount</th></tr>"+acctRows+"</table><h3>Bookings ("+mB.length+")</h3><table><tr><th>Customer</th><th>Dest.</th><th>Date</th><th>Sale</th><th>Cost</th><th>Comm.</th><th>Profit</th><th>Status</th><th>Account</th></tr>"+rows1+"</table><h3>Expenses ("+mE.length+")</h3><table><tr><th>Description</th><th>Category</th><th>Date</th><th>Amount</th><th>Account</th></tr>"+rows2+"</table><div class='foot'>"+AGENCY.name+" "+AGENCY.glNo+"<br>"+AGENCY.address+"<br>"+AGENCY.phone1+" / "+AGENCY.phone2+" | "+AGENCY.email2+"</div></div></body></html>";
    w.document.write(html);w.document.close();setTimeout(function(){w.print();},400);
  };

  return(<div>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16,flexWrap:"wrap",gap:10}}>
      <h2 style={{margin:0,fontSize:16,fontWeight:800,color:C.accent}}>Reports</h2>
      <div style={{display:"flex",gap:7,alignItems:"center",flexWrap:"wrap"}}>
        <div style={{display:"flex",background:C.white,border:"1.5px solid "+C.border,borderRadius:8,overflow:"hidden"}}>
          <button onClick={function(){setMode("month");}} style={{padding:"7px 14px",border:"none",background:mode==="month"?C.accent:"transparent",color:mode==="month"?"#fff":C.muted,fontWeight:700,cursor:"pointer",fontSize:12}}>Monthly</button>
          <button onClick={function(){setMode("year");}} style={{padding:"7px 14px",border:"none",background:mode==="year"?C.accent:"transparent",color:mode==="year"?"#fff":C.muted,fontWeight:700,cursor:"pointer",fontSize:12}}>Yearly</button>
        </div>
        {mode==="month"&&<select value={mo} onChange={function(e){setMo(Number(e.target.value));}} style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:8,padding:"7px 10px",fontSize:12,color:C.textBody,outline:"none"}}>
          {MONTHS.map(function(m,i){return <option key={m} value={i}>{m}</option>;})}
        </select>}
        <select value={mode==="year"?yrOnly:yr} onChange={function(e){mode==="year"?setYrOnly(Number(e.target.value)):setYr(Number(e.target.value));}} style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:8,padding:"7px 10px",fontSize:12,color:C.textBody,outline:"none"}}>
          {[2023,2024,2025,2026,2027].map(function(y){return <option key={y}>{y}</option>;})}
        </select>
        <button onClick={printRep} style={{background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"7px 14px",fontWeight:800,cursor:"pointer",fontSize:12}}>Print Report</button>
      </div>
    </div>
    <div style={{display:"flex",gap:10,flexWrap:"wrap",marginBottom:18}}>
      <Stat icon="💰" label="Revenue"        value={pkr(mRev)}    color={C.accent}/>
      <Stat icon="📈" label="Booking Profit" value={pkr(mProfit)} color={C.gold}/>
      <Stat icon="📤" label="Expenses"       value={pkr(mExp)}    color={C.red}/>
      <Stat icon="🏦" label="Net Profit"     value={pkr(mPro)}    color={mPro>=0?C.gold:C.red}/>
      <Stat icon="⏳" label="Pending"        value={pkr(pend)}    color="#d97706"/>
    </div>
    <div style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:14,padding:16,boxShadow:C.shadow,marginBottom:16}}>
      <div style={{fontWeight:800,color:C.accent,fontSize:12,marginBottom:10}}>Account-wise Income — {period}</div>
      {Object.keys(acct).length===0?<div style={{color:C.muted,fontSize:13}}>Koi paid booking nahi</div>
      :Object.entries(acct).map(function(kv){return(
        <div key={kv[0]} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid "+C.border}}>
          <span style={{fontWeight:700}}>{kv[0]}</span><span style={{color:C.accent,fontWeight:800}}>{pkr(kv[1])}</span>
        </div>
      );})}
    </div>
    <div style={{display:"flex",gap:14,flexWrap:"wrap"}}>
      <div style={{flex:1.5,minWidth:240,background:C.white,border:"1.5px solid "+C.border,borderRadius:14,overflow:"auto",boxShadow:C.shadow}}>
        <div style={{fontWeight:800,color:C.accent,fontSize:11,padding:"10px 12px",borderBottom:"1px solid "+C.border}}>Bookings ({mB.length})</div>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:11,minWidth:420}}>
          <thead><tr style={{background:C.accentSoft}}>{["Customer","Dest.","Sale","Cost","Profit","Status"].map(function(h){return <th key={h} style={{padding:"7px 10px",textAlign:"left",color:C.accent,fontWeight:800,fontSize:9,textTransform:"uppercase"}}>{h}</th>;})}</tr></thead>
          <tbody>
            {mB.map(function(b,i){var p=Number(b.amount)-Number(b.cost||0)-Number(b.commission||0);return(
              <tr key={b.id} style={{borderTop:"1px solid "+C.border,background:i%2===0?"#fff":"#fafffe"}}>
                <td style={{padding:"7px 10px",fontWeight:600}}>{b.customer}</td>
                <td style={{padding:"7px 10px",color:C.muted}}>{b.destination}</td>
                <td style={{padding:"7px 10px",color:C.accent,fontWeight:700}}>{pkr(b.amount)}</td>
                <td style={{padding:"7px 10px",color:C.red,fontSize:10}}>{pkr(b.cost||0)}</td>
                <td style={{padding:"7px 10px",color:p>=0?C.gold:C.red,fontWeight:700}}>{pkr(p)}</td>
                <td style={{padding:"7px 10px"}}><Badge status={b.status}/></td>
              </tr>
            );})}
            {mB.length===0&&<tr><td colSpan={6} style={{padding:14,textAlign:"center",color:C.muted}}>Koi booking nahi</td></tr>}
          </tbody>
        </table>
      </div>
      <div style={{flex:1,minWidth:180,background:C.white,border:"1.5px solid "+C.border,borderRadius:14,padding:14,boxShadow:C.shadow}}>
        <div style={{fontWeight:800,color:C.accent,fontSize:11,marginBottom:10}}>Expense by Category</div>
        {Object.keys(expCat).length===0?<div style={{color:C.muted,fontSize:12}}>Koi expense nahi</div>
        :Object.entries(expCat).map(function(kv){return(
          <div key={kv[0]} style={{marginBottom:10}}>
            <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:3}}>
              <span style={{fontWeight:600}}>{kv[0]}</span><span style={{color:C.red,fontWeight:700}}>{pkr(kv[1])}</span>
            </div>
            <div style={{height:5,background:"#dcfce7",borderRadius:4}}>
              <div style={{width:Math.min(100,(kv[1]/mExp)*100)+"%",height:"100%",background:C.accent,borderRadius:4}}/>
            </div>
          </div>
        );})}
      </div>
    </div>
  </div>);
}

// ─── MARKETING TAB ─────────────────────────────────────────
function Marketing(props){
  var packages=props.packages,setPackages=props.setPackages,customers=props.customers,showToast=props.showToast;
  var ep={name:"",destination:"",duration:"",price:"",includes:"",highlight:""};
  var [pf,setPf]=useState(ep);var [showP,setShowP]=useState(false);var [editId,setEditId]=useState(null);
  var [msg,setMsg]=useState("Olympia Travel & Tours\n\nAssalam o Alaikum!\n\nHamari khaas offers:\n\n[PACKAGES]\n\nBooking:\n+92-331-2351419 / +92-339-4236777\nolympiatraveltours@gmail.com\nOffice No. SF-18, 2nd Floor, Lavish Mall, Tariq Road, Karachi");
  var [ptitle,setPtitle]=useState("Special Offers This Season!");
  var [sel,setSel]=useState([]);var [copied,setCopied]=useState(false);
  var forMsg=sel.length>0?packages.filter(function(p){return sel.includes(p.id);}):packages;
  var lines=forMsg.map(function(p){return p.name+" - "+p.destination+"\n"+p.duration+"\n"+pkr(p.price)+"\n"+p.includes+(p.highlight?"\n"+p.highlight:"");}).join("\n\n");
  var finalMsg=msg.replace("[PACKAGES]",lines);
  function saveP(){if(!pf.name||!pf.price)return;var u=editId?packages.map(function(p){return p.id===editId?Object.assign({},pf,{id:editId,price:Number(pf.price)}):p;}):packages.concat([Object.assign({},pf,{id:uid("P"),price:Number(pf.price)})]);setPackages(u);sv("olympia_packages",u);fbSave("olympia_packages",u);showToast();setEditId(null);setPf(ep);setShowP(false);}
  function tog(id){setSel(function(s){return s.includes(id)?s.filter(function(x){return x!==id;}):[].concat(s,[id]);});}
  function sendWA(phone){var n=phone.replace(/[^0-9]/g,"");var f=n.startsWith("92")?n:"92"+n.replace(/^0/,"");window.open("https://wa.me/"+f+"?text="+encodeURIComponent(finalMsg),"_blank");}
  function broadcast(){customers.filter(function(c){return c.phone;}).forEach(function(c,i){setTimeout(function(){sendWA(c.phone);},i*1800);});}
  function copy(){navigator.clipboard.writeText(finalMsg).then(function(){setCopied(true);setTimeout(function(){setCopied(false);},2000);});}
  function printPoster(){
    var ph=forMsg.map(function(p){return "<div class='pkg'><div class='badge'>"+p.highlight+"</div><div class='pn'>"+p.name+"</div><div class='pd'>"+p.destination+"</div><div class='pdu'>"+p.duration+"</div><div class='pi'>"+p.includes+"</div><div class='pp'>"+pkr(p.price)+"</div></div>";}).join("");
    var w=window.open("","_blank");
    var html="<!DOCTYPE html><html><head><title>Poster</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Arial,sans-serif;background:linear-gradient(135deg,#14532d,#16a34a);min-height:100vh;padding:22px}.wrap{max-width:720px;margin:0 auto;background:rgba(255,255,255,.07);border-radius:18px;padding:28px;border:2px solid rgba(255,255,255,.2)}.top{text-align:center;margin-bottom:20px;padding-bottom:16px;border-bottom:2px solid rgba(255,255,255,.2)}.logo{height:70px;width:auto}.pt{color:#fde68a;font-size:20px;font-weight:900;margin:12px 0 20px;text-align:center}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(190px,1fr));gap:14px;margin-bottom:20px}.pkg{background:rgba(255,255,255,.12);border:1.5px solid rgba(255,255,255,.25);border-radius:12px;padding:16px;text-align:center;color:#fff}.badge{background:#fde68a;color:#14532d;border-radius:20px;padding:2px 10px;font-size:10px;font-weight:800;display:inline-block;margin-bottom:7px}.pn{font-size:14px;font-weight:900;margin-bottom:3px}.pd,.pdu{font-size:11px;opacity:.8;margin-bottom:2px}.pi{font-size:10px;opacity:.65;margin-bottom:7px}.pp{font-size:19px;font-weight:900;color:#fde68a}.foot{text-align:center;border-top:2px solid rgba(255,255,255,.2);padding-top:14px}.fn{font-size:15px;font-weight:900;color:#fff;margin-bottom:5px}.fi{font-size:11px;line-height:1.9;color:rgba(255,255,255,.85)}@media print{body{background:linear-gradient(135deg,#14532d,#16a34a)!important;-webkit-print-color-adjust:exact!important}}</style></head><body><div class='wrap'><div class='top'><img src='"+LOGO_URI+"' class='logo'/></div><div class='pt'>"+ptitle+"</div><div class='grid'>"+ph+"</div><div class='foot'><div class='fn'>"+AGENCY.name+"</div><div class='fi'>"+AGENCY.phone1+" / "+AGENCY.phone2+"<br>"+AGENCY.email2+"<br>"+AGENCY.address+"</div></div></div></body></html>";
    w.document.write(html);w.document.close();setTimeout(function(){w.print();},400);
  }
  return(<div>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14,flexWrap:"wrap",gap:10}}>
      <h2 style={{margin:0,fontSize:16,fontWeight:800,color:C.accent}}>Marketing</h2>
      <button onClick={function(){setEditId(null);setPf(ep);setShowP(true);}} style={{background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"8px 14px",fontWeight:800,cursor:"pointer",fontSize:12}}>+ Add Package</button>
    </div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(190px,1fr))",gap:11,marginBottom:16}}>
      {packages.map(function(p){return(
        <div key={p.id} onClick={function(){tog(p.id);}} style={{background:sel.includes(p.id)?"#dcfce7":C.white,border:"2px solid "+(sel.includes(p.id)?C.accent:C.border),borderRadius:12,padding:13,cursor:"pointer",boxShadow:C.shadow,position:"relative"}}>
          {sel.includes(p.id)&&<div style={{position:"absolute",top:6,right:9,color:C.accent,fontSize:15,fontWeight:900}}>OK</div>}
          {p.highlight&&<div style={{background:C.goldBg,color:C.gold,borderRadius:20,padding:"2px 8px",fontSize:10,fontWeight:700,display:"inline-block",marginBottom:5}}>{p.highlight}</div>}
          <div style={{fontWeight:800,fontSize:12,marginBottom:2}}>{p.name}</div>
          <div style={{color:C.muted,fontSize:10,marginBottom:5}}>{p.destination} - {p.duration}</div>
          <div style={{color:C.accent,fontWeight:900,fontSize:15}}>{pkr(p.price)}</div>
          <div style={{display:"flex",gap:4,marginTop:7}} onClick={function(e){e.stopPropagation();}}>
            <button onClick={function(){setEditId(p.id);setPf(Object.assign({},p));setShowP(true);}} style={{flex:1,background:C.accentSoft,border:"1px solid "+C.accent,color:C.accent,borderRadius:6,padding:"3px 0",cursor:"pointer",fontSize:10,fontWeight:700}}>Edit</button>
            <button onClick={function(){var u=packages.filter(function(x){return x.id!==p.id;});setPackages(u);sv("olympia_packages",u);fbSave("olympia_packages",u);showToast();}} style={{flex:1,background:C.redBg,border:"1px solid #fecaca",color:C.red,borderRadius:6,padding:"3px 0",cursor:"pointer",fontSize:10,fontWeight:700}}>Del</button>
          </div>
        </div>
      );})}
    </div>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
      <div style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:14,padding:16,boxShadow:C.shadow}}>
        <div style={{fontWeight:800,color:"#25D366",fontSize:12,marginBottom:10}}>WhatsApp</div>
        <textarea value={msg} onChange={function(e){setMsg(e.target.value);}} rows={5} style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:8,padding:"7px 10px",fontSize:11,color:C.textBody,outline:"none",boxSizing:"border-box",fontFamily:"inherit",resize:"vertical",marginBottom:7}}/>
        <div style={{display:"flex",flexWrap:"wrap",gap:4,marginBottom:8}}>
          {customers.slice(0,6).map(function(c){return <button key={c.id} onClick={function(){sendWA(c.phone);}} style={{background:C.accentSoft,border:"1px solid "+C.border,color:C.textBody,borderRadius:7,padding:"3px 8px",cursor:"pointer",fontSize:10,fontWeight:600}}>{c.name.split(" ")[0]}</button>;})}
        </div>
        <div style={{display:"flex",gap:6}}>
          <button onClick={broadcast} style={{flex:1,background:"#25D366",color:"#fff",border:"none",borderRadius:8,padding:"8px 0",fontWeight:800,cursor:"pointer",fontSize:11}}>Saare ({customers.length})</button>
          <button onClick={copy} style={{background:copied?"#dcfce7":C.accentSoft,border:"1.5px solid "+C.border,color:copied?C.accent:C.textBody,borderRadius:8,padding:"8px 11px",fontWeight:700,cursor:"pointer",fontSize:11}}>{copied?"Copied!":"Copy"}</button>
        </div>
      </div>
      <div style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:14,padding:16,boxShadow:C.shadow}}>
        <div style={{fontWeight:800,color:C.accent,fontSize:12,marginBottom:10}}>Rate Poster</div>
        <input value={ptitle} onChange={function(e){setPtitle(e.target.value);}} placeholder="Poster title" style={{width:"100%",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:8,padding:"7px 10px",fontSize:12,color:C.textBody,outline:"none",boxSizing:"border-box",marginBottom:10}}/>
        <div style={{background:"linear-gradient(135deg,#14532d,#16a34a)",borderRadius:10,padding:10,marginBottom:10}}>
          <div style={{textAlign:"center",marginBottom:7}}>
            <img src={LOGO_URI} alt="logo" style={{height:32,width:"auto"}}/>
            <div style={{color:"#fde68a",fontWeight:900,fontSize:11,marginTop:3}}>{ptitle}</div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:5}}>
            {forMsg.slice(0,4).map(function(p){return(
              <div key={p.id} style={{background:"rgba(255,255,255,.12)",borderRadius:7,padding:7,textAlign:"center",color:"#fff"}}>
                <div style={{background:"#fde68a",color:"#14532d",borderRadius:20,padding:"1px 6px",fontSize:8,fontWeight:800,display:"inline-block",marginBottom:2}}>{p.highlight}</div>
                <div style={{fontWeight:800,fontSize:10}}>{p.name}</div>
                <div style={{color:"#fde68a",fontWeight:900,fontSize:11,marginTop:2}}>{pkr(p.price)}</div>
              </div>
            );})}
          </div>
        </div>
        <button onClick={printPoster} style={{width:"100%",background:"linear-gradient(135deg,#14532d,#16a34a)",color:"#fff",border:"none",borderRadius:8,padding:"9px 0",fontWeight:800,cursor:"pointer",fontSize:12}}>Print Poster</button>
      </div>
    </div>
    {showP&&(<Modal title={editId?"Edit Package":"New Package"} onClose={function(){setShowP(false);setEditId(null);setPf(ep);}}>
      <div style={{display:"flex",flexWrap:"wrap",justifyContent:"space-between"}}>
        <Field label="Package Name" value={pf.name}        onChange={function(v){setPf(Object.assign({},pf,{name:v}));}} half={true}/>
        <Field label="Destination"  value={pf.destination} onChange={function(v){setPf(Object.assign({},pf,{destination:v}));}} half={true}/>
        <Field label="Duration"     value={pf.duration}    onChange={function(v){setPf(Object.assign({},pf,{duration:v}));}} half={true}/>
        <Field label="Price PKR"    value={pf.price}       onChange={function(v){setPf(Object.assign({},pf,{price:v}));}} type="number" half={true}/>
        <Field label="Includes"     value={pf.includes}    onChange={function(v){setPf(Object.assign({},pf,{includes:v}));}}/>
        <Field label="Highlight"    value={pf.highlight}   onChange={function(v){setPf(Object.assign({},pf,{highlight:v}));}} half={true}/>
      </div>
      <button onClick={saveP} style={{width:"100%",background:C.accent,color:"#fff",border:"none",borderRadius:8,padding:"10px 0",fontWeight:800,cursor:"pointer",fontSize:13,marginTop:4}}>Save</button>
    </Modal>)}
  </div>);
}

// ─── MAIN APP ──────────────────────────────────────────────

// ─── PERSONAL EXPENSES COMPONENT ────────────────────────────
function PersonalExpenses(props){
  var personal=props.personal, setPersonal=props.setPersonal, fbStatus=props.fbStatus;

  var [activeSection,setActiveSection]=useState("personal");
  var [filterMode,setFilterMode]=useState("month");
  var [filterMo,setFilterMo]=useState(new Date().getMonth());
  var [filterYr,setFilterYr]=useState(new Date().getFullYear());
  var [showForm,setShowForm]=useState(false);
  var [search,setSearch]=useState("");

  var emptyExp={id:"",desc:"",amount:"",category:"Food",date:new Date().toISOString().split("T")[0],section:"personal",notes:""};
  var [form,setForm]=useState(emptyExp);

  var CATS_PERSONAL=["Food","Transport","Shopping","Health","Entertainment","Clothes","Other"];
  var CATS_FAMILY=["Groceries","Utilities","School Fees","Rent","Medical","Family Outing","Household","Other"];

  function addExpense(){
    if(!form.desc||!form.amount)return;
    var newExp=Object.assign({},form,{id:uid("PE"),amount:Number(form.amount),section:activeSection});
    var newList=personal.concat([newExp]);setPersonal(newList);
    setForm(Object.assign({},emptyExp,{section:activeSection}));
    setShowForm(false);
  }
  function delExpense(id){var newList2=personal.filter(function(e){return e.id!==id;});setPersonal(newList2);}

  var filtered=useMemo(function(){
    return personal.filter(function(e){
      if(e.section!==activeSection)return false;
      if(search&&![e.desc,e.category,e.notes||""].join(" ").toLowerCase().includes(search.toLowerCase()))return false;
      if(filterMode==="all")return true;
      if(!e.date)return false;
      var d=new Date(e.date);
      if(filterMode==="year")return d.getFullYear()===filterYr;
      return d.getMonth()===filterMo&&d.getFullYear()===filterYr;
    });
  },[personal,activeSection,filterMode,filterMo,filterYr,search]);

  var total=filtered.reduce(function(s,e){return s+Number(e.amount);},0);
  var cats=filtered.reduce(function(a,e){a[e.category]=(a[e.category]||0)+Number(e.amount);return a;},{});
  var period=filterMode==="all"?"All Time":filterMode==="year"?String(filterYr):MONTHS[filterMo]+" "+filterYr;

  return(
    <div>
      {/* Header */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14,flexWrap:"wrap",gap:8}}>
        <h2 style={{margin:0,fontSize:15,fontWeight:800,color:C.accent}}>My Personal Expenses</h2>
        <div style={{display:"flex",gap:6,alignItems:"center"}}>
          <div style={{fontSize:10,color:fbStatus==="synced"?C.accent:C.muted,fontWeight:700,padding:"4px 8px",background:fbStatus==="synced"?"#dcfce7":"#f1f5f9",borderRadius:20}}>
            {fbStatus==="synced"?"🟢 Firebase Synced":"💾 Local Only"}
          </div>
          <button onClick={function(){
            var rows=filtered.map(function(e,i){
              return "<tr style='background:"+(i%2===0?"#fff":"#f0fdf4")+"'><td>"+e.date+"</td><td style='font-weight:700'>"+e.desc+"</td><td>"+e.category+"</td><td style='color:#dc2626;font-weight:700'>"+pkr(e.amount)+"</td><td>"+(e.notes||"--")+"</td></tr>";
            }).join("");
            var sectionLabel=activeSection==="personal"?"Personal":"Family";
            var html="<!DOCTYPE html><html><head><title>"+sectionLabel+" Expenses</title><style>*{margin:0;padding:0;box-sizing:border-box}body{font-family:'Segoe UI',Arial,sans-serif;padding:15px;color:#1f2937}.title{font-size:18px;font-weight:900;color:#16a34a;margin-bottom:4px}.sub{color:#6b7280;font-size:12px;margin-bottom:10px}.total{background:#fee2e2;border:1px solid #fecaca;border-radius:8px;padding:8px 14px;margin-bottom:12px;display:inline-block;font-size:14px;font-weight:900;color:#dc2626}table{width:100%;border-collapse:collapse;font-size:11px}th{background:#f0fdf4;color:#16a34a;padding:8px;text-align:left;font-size:9px;font-weight:800;text-transform:uppercase;border-bottom:2px solid #bbf7d0}td{padding:7px 8px;border-bottom:1px solid #e5e7eb}.foot{text-align:center;color:#9ca3af;font-size:9px;margin-top:12px;padding-top:8px;border-top:1px dashed #bbf7d0}@media print{*{-webkit-print-color-adjust:exact!important}}</style></head><body>"
            +"<div class='title'>"+sectionLabel+" Expenses — "+period+"</div>"
            +"<div class='sub'>"+filtered.length+" entries</div>"
            +"<div class='total'>Total: "+pkr(total)+"</div>"
            +"<table><tr><th>Date</th><th>Description</th><th>Category</th><th>Amount</th><th>Notes</th></tr>"+rows+"</table>"
            +"<div class='foot'>Printed: "+new Date().toLocaleDateString("en-PK")+"</div></body></html>";
            var w=window.open("","_blank");w.document.write(html);w.document.close();setTimeout(function(){w.print();},400);
          }} style={{background:activeSection==="personal"?"#0284c7":C.gold,color:"#fff",border:"none",borderRadius:8,padding:"7px 12px",fontWeight:800,cursor:"pointer",fontSize:11}}>🖨️ Print</button>
          <button onClick={function(){setShowForm(true);setForm(Object.assign({},emptyExp,{section:activeSection}));}}
            style={{background:activeSection==="personal"?C.accent:C.gold,color:"#fff",border:"none",borderRadius:8,padding:"7px 14px",fontWeight:800,cursor:"pointer",fontSize:12}}>
            + Add
          </button>
        </div>
      </div>

      {/* Section Toggle */}
      <div style={{display:"flex",gap:0,marginBottom:14,background:C.white,border:"1.5px solid "+C.border,borderRadius:10,overflow:"hidden",width:"fit-content"}}>
        <button onClick={function(){setActiveSection("personal");}} style={{padding:"10px 24px",border:"none",background:activeSection==="personal"?C.accent:"transparent",color:activeSection==="personal"?"#fff":C.muted,fontWeight:800,cursor:"pointer",fontSize:13}}>
          👤 Personal
        </button>
        <button onClick={function(){setActiveSection("family");}} style={{padding:"10px 24px",border:"none",background:activeSection==="family"?C.gold:"transparent",color:activeSection==="family"?"#fff":C.muted,fontWeight:800,cursor:"pointer",fontSize:13}}>
          👨‍👩‍👧 Family
        </button>
      </div>

      {/* Filter Bar */}
      <div style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:12,padding:"10px 14px",marginBottom:14,display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
        <div style={{display:"flex",background:C.accentSoft,border:"1.5px solid "+C.border,borderRadius:8,overflow:"hidden"}}>
          {["all","month","year"].map(function(m){return(
            <button key={m} onClick={function(){setFilterMode(m);}} style={{padding:"6px 11px",border:"none",background:filterMode===m?(activeSection==="personal"?C.accent:C.gold):"transparent",color:filterMode===m?"#fff":C.muted,fontWeight:700,cursor:"pointer",fontSize:11,textTransform:"capitalize"}}>{m==="all"?"All":m==="month"?"Monthly":"Yearly"}</button>
          );})}
        </div>
        {filterMode==="month"&&(
          <select value={filterMo} onChange={function(e){setFilterMo(Number(e.target.value));}} style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:8,padding:"6px 9px",fontSize:12,outline:"none"}}>
            {MONTHS.map(function(m,i){return <option key={m} value={i}>{m}</option>;})}
          </select>
        )}
        {filterMode!=="all"&&(
          <select value={filterYr} onChange={function(e){setFilterYr(Number(e.target.value));}} style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:8,padding:"6px 9px",fontSize:12,outline:"none"}}>
            {[2023,2024,2025,2026,2027].map(function(y){return <option key={y}>{y}</option>;})}
          </select>
        )}
        <input value={search} onChange={function(e){setSearch(e.target.value);}} placeholder="Search..."
          style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:8,padding:"6px 10px",fontSize:12,outline:"none",minWidth:120}}/>
        <div style={{color:C.muted,fontSize:11,marginLeft:"auto",fontWeight:600}}>{period}</div>
      </div>

      {/* Stats */}
      <div style={{display:"flex",gap:10,marginBottom:14,flexWrap:"wrap"}}>
        <div style={{flex:1,minWidth:120,background:activeSection==="personal"?C.accentSoft:"#fffbeb",border:"1.5px solid "+(activeSection==="personal"?C.border:"#fde68a"),borderRadius:12,padding:"14px 16px",textAlign:"center"}}>
          <div style={{color:C.muted,fontSize:9,fontWeight:700,textTransform:"uppercase",marginBottom:4}}>Total {period}</div>
          <div style={{color:activeSection==="personal"?C.red:C.gold,fontWeight:900,fontSize:20}}>{pkr(total)}</div>
          <div style={{color:C.muted,fontSize:10,marginTop:2}}>{filtered.length} entries</div>
        </div>
        {Object.entries(cats).sort(function(a,b){return b[1]-a[1];}).slice(0,3).map(function(kv){return(
          <div key={kv[0]} style={{flex:1,minWidth:100,background:C.white,border:"1.5px solid "+C.border,borderRadius:12,padding:"14px 16px",textAlign:"center"}}>
            <div style={{color:C.muted,fontSize:9,fontWeight:700,textTransform:"uppercase",marginBottom:4}}>{kv[0]}</div>
            <div style={{color:C.red,fontWeight:800,fontSize:16}}>{pkr(kv[1])}</div>
            <div style={{color:C.muted,fontSize:10}}>{total>0?Math.round((kv[1]/total)*100):0}%</div>
          </div>
        );})}
      </div>

      {/* Category Breakdown */}
      {Object.keys(cats).length>0&&(
        <div style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:12,padding:14,marginBottom:14,boxShadow:C.shadow}}>
          <div style={{fontWeight:800,color:C.accent,fontSize:12,marginBottom:10}}>Category Breakdown</div>
          <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
            {Object.entries(cats).sort(function(a,b){return b[1]-a[1];}).map(function(kv){return(
              <div key={kv[0]} style={{flex:1,minWidth:100,background:C.accentSoft,border:"1px solid "+C.border,borderRadius:9,padding:"9px 11px"}}>
                <div style={{fontWeight:700,fontSize:11,marginBottom:2}}>{kv[0]}</div>
                <div style={{color:C.red,fontWeight:800,fontSize:13}}>{pkr(kv[1])}</div>
                <div style={{height:4,background:"#dcfce7",borderRadius:4,marginTop:5}}>
                  <div style={{width:Math.min(100,(kv[1]/total)*100)+"%",height:"100%",background:activeSection==="personal"?C.accent:C.gold,borderRadius:4}}/>
                </div>
                <div style={{color:C.muted,fontSize:9,marginTop:2}}>{total>0?Math.round((kv[1]/total)*100):0}%</div>
              </div>
            );})}
          </div>
        </div>
      )}

      {/* Expense List */}
      <div style={{background:C.white,border:"1.5px solid "+C.border,borderRadius:14,overflow:"auto",boxShadow:C.shadow}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12,minWidth:420}}>
          <thead><tr style={{background:C.accentSoft}}>
            {["Date","Description","Category","Amount","Notes",""].map(function(h){return <th key={h} style={{padding:"9px 11px",textAlign:"left",color:C.accent,fontWeight:800,fontSize:9,textTransform:"uppercase"}}>{h}</th>;})}
          </tr></thead>
          <tbody>
            {filtered.sort(function(a,b){return new Date(b.date)-new Date(a.date);}).map(function(e,i){return(
              <tr key={e.id} style={{borderTop:"1px solid "+C.border,background:i%2===0?"#fff":"#fafffe"}}>
                <td style={{padding:"9px 11px",color:C.muted,fontSize:11}}>{e.date}</td>
                <td style={{padding:"9px 11px",fontWeight:700}}>{e.desc}</td>
                <td style={{padding:"9px 11px"}}>
                  <span style={{background:activeSection==="personal"?"#dcfce7":"#fef9c3",color:activeSection==="personal"?C.accent:C.gold,padding:"2px 8px",borderRadius:20,fontSize:10,fontWeight:700}}>{e.category}</span>
                </td>
                <td style={{padding:"9px 11px",color:C.red,fontWeight:800}}>{pkr(e.amount)}</td>
                <td style={{padding:"9px 11px",fontSize:10,color:C.muted}}>{e.notes||"--"}</td>
                <td style={{padding:"9px 11px"}}>
                  <button onClick={function(){delExpense(e.id);}} style={{background:C.redBg,border:"1px solid #fecaca",color:C.red,borderRadius:5,padding:"3px 7px",cursor:"pointer",fontSize:10,fontWeight:700}}>Del</button>
                </td>
              </tr>
            );})}
            {filtered.length===0&&<tr><td colSpan={6} style={{padding:18,textAlign:"center",color:C.muted}}>Koi expense nahi — + Add button se add karein</td></tr>}
          </tbody>
        </table>
      </div>

      {/* Add Form Modal */}
      {showForm&&(
        <Modal title={"Add "+(activeSection==="personal"?"Personal":"Family")+" Expense"} onClose={function(){setShowForm(false);}}>
          <div style={{display:"flex",flexWrap:"wrap",justifyContent:"space-between"}}>
            <Field label="Description" value={form.desc} onChange={function(v){setForm(Object.assign({},form,{desc:v}));}}/>
            <Field label="Category" value={form.category} onChange={function(v){setForm(Object.assign({},form,{category:v}));}}
              options={activeSection==="personal"?CATS_PERSONAL:CATS_FAMILY} half={true}/>
            <Field label="Date" value={form.date} onChange={function(v){setForm(Object.assign({},form,{date:v}));}} type="date" half={true}/>
            <Field label="Amount (PKR)" value={form.amount} onChange={function(v){setForm(Object.assign({},form,{amount:v}));}} type="number" half={true}/>
            <Field label="Notes (optional)" value={form.notes||""} onChange={function(v){setForm(Object.assign({},form,{notes:v}));}} half={true}/>
          </div>
          <button onClick={addExpense} style={{width:"100%",background:activeSection==="personal"?C.accent:C.gold,color:"#fff",border:"none",borderRadius:8,padding:"11px 0",fontWeight:800,cursor:"pointer",fontSize:14,marginTop:4}}>
            + Add Expense
          </button>
        </Modal>
      )}
    </div>
  );
}



// ─── EXPENSE ADDER COMPONENT ────────────────────────────────
function ExpenseAdder(props){
  var expenses=props.expenses||[];
  var [ed,setEd]=useState("");
  var [ea,setEa]=useState("");
  return(
    <div>
      <div style={{display:"flex",gap:5,marginBottom:6}}>
        <input value={ed} onChange={function(e){setEd(e.target.value);}} placeholder="Description"
          style={{flex:2,background:"#fff",border:"1.5px solid #fde68a",borderRadius:6,padding:"6px 8px",fontSize:11,outline:"none"}}/>
        <input value={ea} onChange={function(e){setEa(e.target.value);}} placeholder="Amount" type="number"
          style={{flex:1,background:"#fff",border:"1.5px solid #fde68a",borderRadius:6,padding:"6px 8px",fontSize:11,outline:"none"}}/>
        <button onClick={function(){if(!ed||!ea)return;props.onAdd(ed,ea);setEd("");setEa("");}}
          style={{background:"#f59e0b",color:"#fff",border:"none",borderRadius:6,padding:"6px 8px",cursor:"pointer",fontWeight:700}}>+</button>
      </div>
      {expenses.map(function(ex,i){return(
        <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"4px 0",borderBottom:"1px solid #fde68a",fontSize:11}}>
          <span>{ex.desc}</span>
          <div style={{display:"flex",gap:5,alignItems:"center"}}>
            <span style={{color:"#dc2626",fontWeight:700}}>{pkr(ex.amount)}</span>
            <button onClick={function(){props.onRemove(i);}}
              style={{background:"#fee2e2",border:"none",color:"#dc2626",borderRadius:4,padding:"1px 5px",cursor:"pointer",fontSize:10}}>x</button>
          </div>
        </div>
      );})}
      <div style={{display:"flex",justifyContent:"space-between",fontWeight:800,color:"#dc2626",marginTop:6,fontSize:12}}>
        <span>Total</span><span>{pkr(props.totalExpenses||0)}</span>
      </div>
    </div>
  );
}





// ─── VISA AGENT TAB ──────────────────────────────────────────
